  1→import { projectPartToView } from '../../domain/viewProjection';
  2→
  3→export function createSketchSelectHandler({ dispatch, editorDispatch, project, activeView, viewport }) {
  4→  function hitTestParts(modelPos) {
  5→    const tolerance = 6 / viewport.zoom;
  6→    const parts = project.parts.filter((p) => p.type !== 'dimension');
  7→
  8→    // Iterate in reverse for top-most first
  9→    for (let i = parts.length - 1; i >= 0; i--) {
 10→      const part = parts[i];
 11→      const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, activeView);
 12→
 13→      if (
 14→        modelPos.x >= svgX - tolerance &&
 15→        modelPos.x <= svgX + svgWidth + tolerance &&
 16→        modelPos.y >= svgY - tolerance &&
 17→        modelPos.y <= svgY + svgHeight + tolerance
 18→      ) {
 19→        return { id: part.id, type: 'part' };
 20→      }
 21→    }
 22→    return null;
 23→  }
 24→
 25→  return {
 26→    onMouseDown(modelPos, e, toolState) {
 27→      if (e.button !== 0) return;
 28→
 29→      const hit = hitTestParts(modelPos);
 30→      if (hit) {
 31→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
 32→        editorDispatch({
 33→          type: 'UPDATE_TOOL_STATE',
 34→          payload: { dragging: true, startPos: modelPos, dragPartId: hit.id },
 35→        });
 36→        return;
 37→      }
 38→
 39→      editorDispatch({ type: 'DESELECT' });
 40→    },
 41→
 42→    onMouseMove(modelPos, e, toolState, selectedId) {
 43→      if (!toolState.dragging || !toolState.startPos || !toolState.dragPartId) return;
 44→
 45→      const dx = modelPos.x - toolState.startPos.x;
 46→      const dy = modelPos.y - toolState.startPos.y;
 47→
 48→      if (Math.abs(dx) < 1 && Math.abs(dy) < 1) return;
 49→
 50→      const part = project.parts.find((p) => p.id === toolState.dragPartId);
 51→      if (!part) return;
 52→
 53→      // Compute position delta based on view
 54→      const pos = { ...part.position };
 55→      switch (activeView) {
 56→        case 'top':
 57→          pos.x += dx;
 58→          pos.y += dy;
 59→          break;
 60→        case 'front':
 61→          pos.x += dx;
 62→          pos.z -= dy;
 63→          break;
 64→        case 'side':
 65→          pos.y += dx;
 66→          pos.z -= dy;
 67→          break;
 68→      }
 69→
 70→      dispatch({
 71→        type: 'PART_UPDATE',
 72→        part: { id: toolState.dragPartId, position: pos },
 73→      });
 74→
 75→      editorDispatch({
 76→        type: 'UPDATE_TOOL_STATE',
 77→        payload: { startPos: modelPos },
 78→      });
 79→    },
 80→
 81→    onMouseUp(modelPos, e, toolState) {
 82→      if (toolState.dragging) {
 83→        editorDispatch({
 84→          type: 'UPDATE_TOOL_STATE',
 85→          payload: { dragging: false, startPos: null, dragPartId: null },
 86→        });
 87→      }
 88→    },
 89→
 90→    onKeyDown(e, toolState, selectedId) {
 91→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
 92→        dispatch({ type: 'PART_DELETE', partId: selectedId });
 93→        editorDispatch({ type: 'DESELECT' });
 94→      }
 95→    },
 96→
 97→    getCursor(toolState) {
 98→      if (toolState?.dragging) return 'grabbing';
 99→      return 'default';
100→    },
101→  };
102→}
