  1→import { createPanel, createLeg, createFrame, createCutout, createHole } from '../../domain/partModels';
  2→import { viewToModelPosition, viewToModelExtents } from '../../domain/viewProjection';
  3→
  4→const partFactories = {
  5→  panel: createPanel,
  6→  leg: createLeg,
  7→  frame: createFrame,
  8→  cutout: createCutout,
  9→  hole: createHole,
 10→};
 11→
 12→export function createPartPlaceHandler({ dispatch, editorDispatch, activeView, activeAssemblyId, partType, selectedId, project }) {
 13→  const needsParent = partType === 'cutout' || partType === 'hole';
 14→
 15→  return {
 16→    onMouseDown(modelPos, e, toolState) {
 17→      if (e.button !== 0) return;
 18→
 19→      if (needsParent) {
 20→        const parentPart = selectedId ? project.parts.find((p) => p.id === selectedId) : null;
 21→        if (!parentPart || parentPart.type !== 'panel') {
 22→          editorDispatch({
 23→            type: 'SET_STATUS_MESSAGE',
 24→            message: `Select a panel first to place a ${partType}.`,
 25→          });
 26→          return;
 27→        }
 28→      }
 29→
 30→      editorDispatch({
 31→        type: 'UPDATE_TOOL_STATE',
 32→        payload: {
 33→          drawing: true,
 34→          startPos: { x: modelPos.x, y: modelPos.y },
 35→          currentPos: { x: modelPos.x, y: modelPos.y },
 36→        },
 37→      });
 38→    },
 39→
 40→    onMouseMove(modelPos, e, toolState) {
 41→      if (!toolState.drawing) return;
 42→
 43→      editorDispatch({
 44→        type: 'UPDATE_TOOL_STATE',
 45→        payload: {
 46→          currentPos: { x: modelPos.x, y: modelPos.y },
 47→        },
 48→      });
 49→    },
 50→
 51→    onMouseUp(modelPos, e, toolState) {
 52→      if (!toolState.drawing || !toolState.startPos) return;
 53→
 54→      const x = Math.min(toolState.startPos.x, modelPos.x);
 55→      const y = Math.min(toolState.startPos.y, modelPos.y);
 56→      const svgW = Math.abs(modelPos.x - toolState.startPos.x);
 57→      const svgH = Math.abs(modelPos.y - toolState.startPos.y);
 58→
 59→      const minSize = 10; // mm
 60→      if (svgW > minSize && svgH > minSize) {
 61→        const position = viewToModelPosition(x, y, activeView);
 62→        const extents = viewToModelExtents(svgW, svgH, activeView, partType);
 63→
 64→        const factory = partFactories[partType];
 65→        if (!factory) return;
 66→
 67→        const overrides = {
 68→          position,
 69→          ...extents,
 70→        };
 71→
 72→        if (needsParent) {
 73→          overrides.parentId = selectedId;
 74→        }
 75→
 76→        const part = factory(overrides);
 77→
 78→        dispatch({ type: 'PART_ADD', part });
 79→
 80→        if (activeAssemblyId) {
 81→          dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
 82→        }
 83→
 84→        editorDispatch({
 85→          type: 'SET_STATUS_MESSAGE',
 86→          message: `${partType}: ${Math.round(svgW)} x ${Math.round(svgH)} mm`,
 87→        });
 88→      }
 89→
 90→      editorDispatch({
 91→        type: 'UPDATE_TOOL_STATE',
 92→        payload: {
 93→          drawing: false,
 94→          startPos: null,
 95→          currentPos: null,
 96→        },
 97→      });
 98→    },
 99→
100→    onKeyDown(e) {
101→      if (e.key === 'Escape') {
102→        editorDispatch({
103→          type: 'UPDATE_TOOL_STATE',
104→          payload: {
105→            drawing: false,
106→            startPos: null,
107→            currentPos: null,
108→          },
109→        });
110→      }
111→    },
112→
113→    getCursor(toolState) {
114→      return 'crosshair';
115→    },
116→  };
117→}
