 3→function projectDimensionPoint(point, view) {
 4→  switch (view) {
 5→    case 'top':
 6→      return { x: point.x, y: point.y };
 7→    case 'front':
 8→      return { x: point.x, y: -(point.z || 0) };
 9→    case 'side':
10→      return { x: point.y, y: -(point.z || 0) };
11→    default:
12→      return { x: point.x, y: point.y };
13→  }
14→}
15→
16→export default function DimensionRenderer({ dimension, view, zoom = 1 }) {
17→  const start2D = projectDimensionPoint(dimension.startPoint, view);
18→  const end2D = projectDimensionPoint(dimension.endPoint, view);
19→
20→  const figure = createDimensionFigure({
21→    id: dimension.id,
22→    startPoint: start2D,
23→    endPoint: end2D,
24→    mode: 'aligned',
25→    offset: dimension.offset || 200,
26→    label: dimension.textOverride || undefined,
27→    source: 'manual',
28→  });
29→
30→  if (!figure) return null;
31→
32→  return (
33→    <g data-part-id={dimension.id} style={{ pointerEvents: 'none' }}>
34→      {/* Extension lines */}
35→      {figure.extensionLines.map((line, i) => (
36→        <line
37→          key={`ext-${i}`}
38→          x1={line.start.x}
39→          y1={line.start.y}
40→          x2={line.end.x}
41→          y2={line.end.y}
42→          stroke="#666"
43→          strokeWidth={1}
44→          vectorEffect="non-scaling-stroke"
45→        />
46→      ))}
47→
48→      {/* Dimension line */}
49→      <line
50→        x1={figure.lineStart.x}
51→        y1={figure.lineStart.y}
52→        x2={figure.lineEnd.x}
53→        y2={figure.lineEnd.y}
54→        stroke="#1E2433"
55→        strokeWidth={1}
56→        vectorEffect="non-scaling-stroke"
57→      />
58→
59→      {/* Arrowheads */}
60→      {figure.arrowheads.map((arrow, i) => (
61→        <polygon
62→          key={`arrow-${i}`}
63→          points={`${arrow.tip.x},${arrow.tip.y} ${arrow.left.x},${arrow.left.y} ${arrow.right.x},${arrow.right.y}`}
64→          fill="#1E2433"
65→        />
66→      ))}
67→
68→      {/* Text label */}
69→      <text
70→        x={figure.text.position.x}
71→        y={figure.text.position.y}
72→        textAnchor="middle"
73→        dominantBaseline="central"
74→        transform={`rotate(${figure.text.angle} ${figure.text.position.x} ${figure.text.position.y})`}
75→        fontSize={120}
76→        fontFamily="var(--font-blueprint, monospace)"
77→        fill="#1E2433"
78→      >
79→        {figure.text.value}
80→      </text>
81→    </g>
82→  );
83→}
