  1→import { useRef, useEffect, useCallback } from 'react';
  2→import * as THREE from 'three';
  3→import { useSketch } from '../app/SketchProvider';
  4→import { useSketchEditor } from '../app/SketchEditorProvider';
  5→import { buildSketchPreviewRoot } from './buildSketchPreview';
  6→import { createPreviewViewport } from '@/three/viewer/createPreviewViewport';
  7→import { disposeScene } from '@/three/viewer/disposeScene';
  8→import styles from './SketchPreviewPanel.module.css';
  9→
 10→export default function SketchPreviewPanel() {
 11→  const containerRef = useRef(null);
 12→  const viewportRef = useRef(null);
 13→  const rootRef = useRef(null);
 14→
 15→  const { project } = useSketch();
 16→  const { selectedId } = useSketchEditor();
 17→
 18→  // Initialize viewport
 19→  useEffect(() => {
 20→    const container = containerRef.current;
 21→    if (!container) return;
 22→
 23→    const viewport = createPreviewViewport(container);
 24→    viewportRef.current = viewport;
 25→
 26→    return () => {
 27→      if (rootRef.current) {
 28→        disposeScene(rootRef.current, { disposeMaterials: true });
 29→        rootRef.current = null;
 30→      }
 31→      viewport.dispose();
 32→      viewportRef.current = null;
 33→    };
 34→  }, []);
 35→
 36→  // Update scene when parts change
 37→  useEffect(() => {
 38→    const viewport = viewportRef.current;
 39→    if (!viewport) return;
 40→
 41→    // Dispose old root
 42→    if (rootRef.current) {
 43→      disposeScene(rootRef.current, { disposeMaterials: true });
 44→    }
 45→
 46→    const root = buildSketchPreviewRoot(project.parts, selectedId);
 47→    rootRef.current = root;
 48→
 49→    // Compute bounds from parts
 50→    const box = new THREE.Box3();
 51→    root.updateMatrixWorld(true);
 52→    box.expandByObject(root);
 53→
 54→    if (box.isEmpty()) {
 55→      box.set(
 56→        new THREE.Vector3(-500, 0, -300),
 57→        new THREE.Vector3(500, 800, 300)
 58→      );
 59→    }
 60→
 61→    const bounds = {
 62→      min: { x: box.min.x, y: box.min.y, z: box.min.z },
 63→      max: { x: box.max.x, y: box.max.y, z: box.max.z },
 64→    };
 65→
 66→    viewport.setWorld(root, bounds, 0);
 67→  }, [project.parts, selectedId]);
 68→
 69→  // ResizeObserver
 70→  useEffect(() => {
 71→    const container = containerRef.current;
 72→    const viewport = viewportRef.current;
 73→    if (!container || !viewport) return;
 74→
 75→    const observer = new ResizeObserver(() => viewport.resize());
 76→    observer.observe(container);
 77→    return () => observer.disconnect();
 78→  }, []);
 79→
 80→  const handleResetView = useCallback(() => {
 81→    viewportRef.current?.resetView();
 82→  }, []);
 83→
 84→  return (
 85→    <div className={styles.panel}>
 86→      <div className={styles.header}>
 87→        <span>3D Preview</span>
 88→        <button className={styles.resetBtn} onClick={handleResetView} title="Reset view">
 89→          <svg viewBox="0 0 16 16" width="14" height="14">
 90→            <path d="M2 8a6 6 0 1 1 1.2 3.6" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" />
 91→            <path d="M2 12V8h4" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
 92→          </svg>
 93→        </button>
 94→      </div>
 95→      <div ref={containerRef} className={styles.viewport} />
 96→      <div className={styles.footer}>Orbit: drag | Zoom: scroll</div>
 97→    </div>
 98→  );
 99→}
